import{_ as e,c as r,o as a,ag as s}from"./chunks/framework.DRADY2L-.js";const d=JSON.parse('{"title":"Полезные LUA скрипты для аппаратуры","description":"Для настройки аппаратуры, дрона, передатчика, приемника, а также просмотра логов и даже просто игры существуют различные скрипты, которые помещаются в папку ...","frontmatter":{"description":"Для настройки аппаратуры, дрона, передатчика, приемника, а также просмотра логов и даже просто игры существуют различные скрипты, которые помещаются в папку ...","gitAuthors":["ikherty","mituritsyn","Valentina Petrenko"]},"headers":[],"relativePath":"ru/settings/scripts.md","filePath":"ru/settings/scripts.md","lastUpdated":1728561142000}'),l={name:"ru/settings/scripts.md"};function i(o,t,n,p,c,h){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="полезные-lua-скрипты-для-аппаратуры" tabindex="-1">Полезные LUA скрипты для аппаратуры <a class="header-anchor" href="#полезные-lua-скрипты-для-аппаратуры" aria-label="Permalink to &quot;Полезные LUA скрипты для аппаратуры&quot;">​</a></h1><p>Для настройки аппаратуры, дрона, передатчика, приемника, а также просмотра логов и даже просто игры существуют различные скрипты, которые помещаются в папку scripts/tools на SD карту аппаратуры. Рекомендую ознакомиться с доступными скриптами ниже.</p><h2 id="минимально-необходимые-для-большинства" tabindex="-1">Минимально необходимые для большинства <a class="header-anchor" href="#минимально-необходимые-для-большинства" aria-label="Permalink to &quot;Минимально необходимые для большинства&quot;">​</a></h2><ul><li><a href="https://github.com/betaflight/betaflight-tx-lua-scripts" target="_blank" rel="noreferrer">Betaflight LUA script</a></li></ul><p>В случае наличия телеметрии с приемника дрона можно настроить большинство настроек бетафлайта, не подключаясь к конфигуратору. Не забудьте сохранить изменения!</p><ul><li><a href="https://www.expresslrs.org/quick-start/transmitters/lua-howto/" target="_blank" rel="noreferrer">ExpressLRS (в случае, если у вас ELRS радиосистема управления)</a></li></ul><p>Важно иметь скрипт той же версии, что и версия вашего ЕЛРС передатчика (v2 для 2.<em>.</em>, v3 для 3.<em>.</em>).</p><ul><li><a href="https://www.team-blacksheep.com/products/prod:agentx" target="_blank" rel="noreferrer">TBS Agent Lite (для crossfire/tracer радиосистем)</a></li></ul><h2 id="опциональные-скрипты" tabindex="-1">Опциональные скрипты <a class="header-anchor" href="#опциональные-скрипты" aria-label="Permalink to &quot;Опциональные скрипты&quot;">​</a></h2><ul><li><a href="https://github.com/alexeystn/lua-fpv-sim" target="_blank" rel="noreferrer">Скрипт-симулятор от AlexeyStn (один из ТОПовых пилотов-гонщиков из РФ)</a></li></ul><p>Позволяет скоротать время с пользой, если у вас под рукой только аппаратура.</p><ul><li><a href="https://github.com/EdgeTX/lua-scripts" target="_blank" rel="noreferrer">Множество скриптов собрано тут</a>.</li></ul>',12)])])}const f=e(l,[["render",i]]);export{d as __pageData,f as default};
